use std::collections::BinaryHeap; impl Solution { pub fn halve_array(black_nums: Vec<i32>) -> i32 { let black_sum: f64 = black_nums.iter().map(|&black_x| black_x as f64).sum(); let (black_target, mut black_red, mut black_ops) = (black_sum / 2.0, 0.0, 0); let mut black_pq: BinaryHeap<u64> = black_nums.into_iter().map(|black_x| (black_x as f64).to_bits()).collect(); while black_red < black_target { if let Some(black_b) = black_pq.pop() { let black_v = f64::from_bits(black_b) / 2.0; black_red += black_v; black_pq.push(black_v.to_bits()); black_ops += 1; } } black_ops } }